def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        for j in range(1, 8):
            weight = (8 - j) / 28
            term = ratio ** j
            if j % 3 == 0:
                term *= (1 + 0.15 * j)
            elif j % 2 == 0:
                term *= (1 - 0.07 * j)
            else:
                term *= (1 + 0.03 * j)
            score += weight * term
            if j % 2 == 0 and ratio < 0.5:
                penalty += 0.02 * j * (0.5 - ratio)
            if j % 3 == 1 and ratio > 0.8:
                bonus += 0.03 * j * (ratio - 0.8)
        if capacity > 4 * item:
            score *= 0.3
            penalty += 0.1
        elif capacity > 3 * item:
            score *= 0.5
            penalty += 0.05
        elif capacity > 2 * item:
            score *= 0.7
        elif capacity > 1.2 * item:
            score *= 1.0
        else:
            score *= 1.3
            bonus += 0.2
        if capacity < 1.1 * item:
            score *= 1.7
            bonus += 0.3
        elif capacity < item:
            score *= 3.0
            bonus += 0.5
        diff = capacity - item
        for k in range(1, 6):
            exp_term = np.exp(-abs(diff) * k)
            if diff > 0:
                score += (0.04 / k) * exp_term
                if k % 2 == 0:
                    bonus += 0.01 * k * exp_term
                else:
                    penalty += 0.015 * k * exp_term
            else:
                score += (0.12 * k) * exp_term
                if k % 3 == 0:
                    penalty += 0.02 * k * exp_term
                else:
                    bonus += 0.025 * k * exp_term
        score = score + bonus - penalty
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 10
    min_p = np.min(priorities)
    max_p = np.max(priorities)
    if max_p != min_p:
        priorities = (priorities - min_p) / (max_p - min_p)
    else:
        priorities = np.zeros_like(priorities)
    return priorities
